import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { useCart } from '../context/CartContext';
import toast from 'react-hot-toast';
import './Cart.css';

export default function Cart() {
    const { cart, total, count, loading, remove, update, clear, placeOrder } = useCart();
    const [ordering, setOrdering] = useState(false);
    const [ordered, setOrdered] = useState(null);

    const handleCheckout = async() => {
        setOrdering(true);
        try {
            const result = await placeOrder();
            setOrdered(result);
            toast.success('Order placed! 🎉');
        } catch (err) {
            toast.error(err.message);
        } finally {
            setOrdering(false);
        }
    };

    if (ordered) {
        return ( <
            div className = "cart-page page-enter" >
            <
            div className = "container order-success" >
            <
            motion.div className = "success-card"
            initial = {
                { scale: 0.8, opacity: 0 } }
            animate = {
                { scale: 1, opacity: 1 } }
            transition = {
                { type: 'spring', stiffness: 200 } } >
            <
            motion.div className = "success-icon"
            animate = {
                { rotate: [0, 10, -10, 5, -5, 0] } }
            transition = {
                { duration: 0.6, delay: 0.3 } } >
            🎉 < /motion.div> <
            h2 > Order Placed! < /h2> <
            p className = "success-sub" >
            Order < strong > { ordered.orderId } < /strong> confirmed. <
            /p> <
            p className = "success-eta" > 📦{ ordered.estimatedDelivery } < /p> <
            Link to = "/products"
            className = "btn btn-primary" >
            Continue Shopping <
            /Link> <
            /motion.div> <
            /div> <
            /div>
        );
    }

    return ( <
        div className = "cart-page page-enter" >
        <
        div className = "container" >

        { /* Header */ } <
        div className = "cart-header" >
        <
        h1 className = "cart-title" > Your Cart < /h1> {
            count > 0 && ( <
                button className = "btn btn-ghost clear-btn"
                onClick = { clear } >
                Clear All <
                /button>
            )
        } <
        /div>

        { /* Loading */ } {
            loading ? ( <
                div style = {
                    { display: 'flex', justifyContent: 'center', padding: '80px 0' } } >
                <
                div className = "spinner" / >
                <
                /div>

                /* Empty Cart */
            ) : cart.length === 0 ? ( <
                motion.div className = "empty-cart"
                initial = {
                    { opacity: 0, y: 20 } }
                animate = {
                    { opacity: 1, y: 0 } } >
                <
                div className = "empty-cart-icon" > 🛒 < /div> <
                h3 > Your cart is empty < /h3> <
                p > Looks like you haven 't added anything yet.</p> <
                Link to = "/products"
                className = "btn btn-primary" >
                Browse Products <
                /Link> <
                /motion.div>

                /* Cart Items */
            ) : ( <
                div className = "cart-layout" >

                { /* Left — Items List */ } <
                div className = "cart-items" >
                <
                AnimatePresence > {
                    cart.map(item => ( <
                        motion.div key = { item.productId }
                        className = "cart-item"
                        layout initial = {
                            { opacity: 0, x: -20 } }
                        animate = {
                            { opacity: 1, x: 0 } }
                        exit = {
                            { opacity: 0, x: 20, height: 0 } }
                        transition = {
                            { duration: 0.3 } } >
                        { /* Image */ } <
                        div className = "item-img-wrap" >
                        <
                        img src = { item.product.image }
                        alt = { item.product.name }
                        className = "item-img" /
                        >
                        <
                        /div>

                        { /* Info */ } <
                        div className = "item-info" >
                        <
                        span className = "item-category" > { item.product.category } < /span> <
                        h3 className = "item-name" > { item.product.name } < /h3> <
                        p className = "item-desc" > { item.product.description } < /p> <
                        /div>

                        { /* Controls */ } <
                        div className = "item-controls" >
                        <
                        div className = "qty-ctrl" >
                        <
                        button className = "qty-btn"
                        onClick = {
                            () => update(item.productId, item.quantity - 1) }
                        disabled = { item.quantity <= 1 } >
                        − < /button> <
                        span className = "qty-val" > { item.quantity } < /span> <
                        button className = "qty-btn"
                        onClick = {
                            () => update(item.productId, item.quantity + 1) } >
                        + < /button> <
                        /div> <
                        span className = "item-price" >
                        $ {
                            (item.product.price * item.quantity).toFixed(2) } <
                        /span> <
                        button className = "remove-btn"
                        onClick = {
                            () => remove(item.productId, item.product.name) } >
                        <
                        svg width = "16"
                        height = "16"
                        viewBox = "0 0 24 24"
                        fill = "none"
                        stroke = "currentColor"
                        strokeWidth = "2" >
                        <
                        polyline points = "3 6 5 6 21 6" / >
                        <
                        path d = "M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a1 1 0 011-1h4a1 1 0 011 1v2" / >
                        <
                        /svg> <
                        /button> <
                        /div> <
                        /motion.div>
                    ))
                } <
                /AnimatePresence> <
                /div>

                { /* Right — Order Summary */ } <
                motion.div className = "order-summary"
                initial = {
                    { opacity: 0, y: 20 } }
                animate = {
                    { opacity: 1, y: 0 } }
                transition = {
                    { delay: 0.2 } } >
                <
                h2 className = "summary-title" > Order Summary < /h2>

                <
                div className = "summary-rows" >
                <
                div className = "summary-row" >
                <
                span > Items({ count }) < /span> <
                span > $ { total } < /span> <
                /div> <
                div className = "summary-row" >
                <
                span > Shipping < /span> <
                span className = "free-tag" > FREE < /span> <
                /div> <
                div className = "summary-row" >
                <
                span > Tax(8 % ) < /span> <
                span > $ {
                    (total * 0.08).toFixed(2) } < /span> <
                /div> <
                /div>

                <
                div className = "summary-total" >
                <
                span > Total < /span> <
                span className = "total-val" > $ {
                    (total * 1.08).toFixed(2) } < /span> <
                /div>

                <
                motion.button className = "checkout-btn"
                onClick = { handleCheckout }
                disabled = { ordering }
                whileTap = {
                    { scale: 0.97 } }
                whileHover = {
                    { boxShadow: '0 0 40px rgba(108,99,255,0.5)' } } >
                {
                    ordering ?
                    < span className = "spinner"
                    style = {
                        { width: 20, height: 20, borderWidth: 2 } }
                    /> :
                        '✦ Place Order'
                } <
                /motion.button>

                <
                Link to = "/products"
                className = "btn btn-ghost continue-shopping" > ←Continue Shopping <
                /Link> <
                /motion.div>

                <
                /div>
